import { sum, result, CATEGORY } from '../util.js'
import { pct, moneyK } from '../../lib/format.js'

// Revenue Concentration — revenue share generated by the top rep.
// High concentration is a key-person dependency the coverage model didn't assume.
// Threshold: top rep >20% of revenue = drifting, >30% = off.
export function revenueConcentration(plan, roster) {
  const totalRev = sum(roster.map((r) => r.revenue))
  const top = roster.reduce(
    (best, r) => (r.revenue > best.revenue ? r : best),
    roster[0],
  )
  const share = totalRev ? top.revenue / totalRev : 0

  const status = share > 0.3 ? 'off' : share > 0.2 ? 'drifting' : 'clean'

  return result({
    id: 'revenueConcentration',
    category: CATEGORY.HIT_NUMBER,
    label: 'Revenue Concentration',
    status,
    designed: { value: 20, unit: '% (ceiling)' },
    actual: { value: share * 100, unit: '%' },
    delta: null,
    summary: `${top.name} generates ${moneyK(top.revenue)} of ${moneyK(
      totalRev,
    )} total revenue (${pct(share)}).`,
    details: {
      topRep: top.name,
      topRevenue: top.revenue,
      totalRev,
      share,
      withoutTop: totalRev - top.revenue,
    },
  })
}
